const crypto = require("crypto");

// ------------------------------
// Config (from your Secrets JSON)
// ------------------------------
const item = $input.first().json;

const entra = item.n8n_secrets?.entra || {};
const tenantId = entra.tenant_id;
const clientId = entra.client_id;
const redirectUri = entra.redirect_uri;
const cookieName = entra.cookie_name;
const allowedDomains = entra.allowed_domains;

// ------------------------------
// Helpers
// ------------------------------
function toQueryString(obj = {}) {
  return Object.entries(obj)
    .filter(([, v]) => v !== undefined && v !== null && v !== "")
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
    .join("&");
}

function getCookie(header, name) {
  if (!header) return null;
  const match = header.match(new RegExp(`(^| )${name}=([^;]+)`));
  return match ? match[2] : null;
}

function redirectToEntra(state) {
  const authority = `https://login.microsoftonline.com/${encodeURIComponent(tenantId)}/oauth2/v2.0/authorize`;

  const location =
    `${authority}` +
    `?client_id=${encodeURIComponent(clientId)}` +
    `&redirect_uri=${encodeURIComponent(redirectUri)}` +
    `&response_type=code` +
    `&response_mode=query` +
    `&scope=${encodeURIComponent("openid profile email")}` +
    `&state=${encodeURIComponent(state)}`;

  return [
    {
      json: {
        statusCode: 302,
        headers: {
          Location: location,
        },
      },
    },
  ];
}

function deny403(message = "Forbidden") {
  return [
    {
      json: {
        statusCode: 403,
        headers: { "Content-Type": "text/plain; charset=utf-8" },
        body: message,
      },
    },
  ];
}

/**
 * Validates if an email domain is in the allowed list
 * @param {string} email 
 * @param {string[]} allowed 
 * @returns {boolean}
 */
function isDomainAllowed(email, allowed) {
  if (!email || !email.includes('@')) return false;

  // Split at '@' and take the second part
  const domain = email.split('@').pop().toLowerCase();

  return allowed.includes(domain);
}

function safeEqual(a, b) {
  const aBuf = Buffer.from(String(a || ""), "utf8");
  const bBuf = Buffer.from(String(b || ""), "utf8");
  if (aBuf.length !== bBuf.length) return false;
  return crypto.timingSafeEqual(aBuf, bBuf);
}

function buildJobAuthMessage({ job, exp, sub }) {
  // fixed order; only include sub if present
  let msg = `job=${String(job)}&exp=${String(exp)}`;
  if (sub) msg += `&sub=${String(sub)}`;
  return msg;
}

function signJobAuth({ secret, job, exp, sub }) {
  const msg = buildJobAuthMessage({ job, exp, sub });
  return crypto.createHmac("sha256", secret).update(msg).digest("base64url");
}

function verifyJobAuth({ secret, job, exp, sub, auth }) {
  if (!secret || !job || !exp || !auth) return false;
  const expected = signJobAuth({ secret, job, exp, sub });
  return safeEqual(auth, expected);
}

// --- CHANGED 2026-03-10: helper for readable UTC expiry logging ---
function formatUtcIsoFriendly(isoString) {
  return new Intl.DateTimeFormat("en-GB", {
    dateStyle: "medium",
    timeStyle: "medium",
    timeZone: "UTC",
  }).format(new Date(isoString));
}

// ------------------------------
// Self-auth link support (auth + number + exp [+ sub])
// ------------------------------
const q = item.query || {};
const jobNumber = q.number;
const exp = q.exp;
const auth = q.auth;
const sub = q.sub; // optional: bind token to an identity / recipient

if (auth && jobNumber && exp) {
  const now = Math.floor(Date.now() / 1000);
  const expNum = Number(exp);

  // --- CHANGED 2026-03-10: debug logging showing provided auth expiry ---
  if (Number.isFinite(expNum)) {
    const expiryIso = new Date(expNum * 1000).toISOString();
    console.log("[AuthGate] Self-auth token provided:", {
      jobNumber,
      sub: sub || null,
      expiresAtIsoUtc: expiryIso,
      expiresAtFriendlyUtc: formatUtcIsoFriendly(expiryIso),
      expired: expNum < now,
    });
  } else {
    console.log("[AuthGate] Self-auth token provided with non-numeric exp:", {
      jobNumber,
      sub: sub || null,
      exp,
    });
  }

  // basic sanity: must be numeric + not expired
  if (!Number.isFinite(expNum) || expNum < now) {
    return deny403("Link expired");
  }

  const ok = verifyJobAuth({
    secret: item.n8n_secrets?.job_link_secret, // add this secret
    job: jobNumber,
    exp: expNum,
    sub,
    auth,
  });

  if (ok) {
    // Bypass Entra/session for this request
    return $input.all();
  }

  return deny403("Invalid link");
}

// ------------------------------
// Build returnTo + state (no URLSearchParams)
// ------------------------------
const qs = toQueryString(item.query || {});
const queryString = qs ? `?${qs}` : "";
const returnTo = `${item.webhookUrl}${queryString}`;

console.log(`Return to`, returnTo);

const state = globalThis.Buffer.from(JSON.stringify({ returnTo })).toString("base64url");

// ------------------------------
// Read + validate session cookie
// ------------------------------
const cookieHeader = item.headers?.cookie || "";
const sessionToken = getCookie(cookieHeader, cookieName);

console.log(`Session token: ${sessionToken}`);

// Missing session → login
if (!sessionToken) {
  return redirectToEntra(state);
}

// Malformed session → login
const parts = sessionToken.split(".");
if (parts.length !== 2) {
  return redirectToEntra(state);
}
const [payloadB64, signature] = parts;

// Verify signature → login on failure
const expectedSig = crypto
  .createHmac("sha256", item.n8n_secrets?.n8n_session_secret)
  .update(payloadB64)
  .digest("hex");

if (signature !== expectedSig) {
  return redirectToEntra(state);
}

// Decode payload
let payload;
try {
  payload = JSON.parse(globalThis.Buffer.from(payloadB64, "base64url").toString("utf8"));
} catch {
  return redirectToEntra(state);
}

console.log(`Payload`, payload);

// Expired → login again (SSO should make this painless)
const now = Math.floor(Date.now() / 1000);
if (!payload.exp || payload.exp < now) {
  return redirectToEntra(state);
}

// ------------------------------
// Log authenticated user identity
// ------------------------------
const effectiveEmail =
  payload.email ||
  payload.preferred_username ||
  "(no email)";

console.log(
  "[AuthGate] Authenticated user:",
  {
    email: effectiveEmail,
    subject: payload.sub,
    expiresAt: payload.exp
      ? new Date(payload.exp * 1000).toISOString()
      : "(no exp)"
  }
);

// ------------------------------
// Domain allow-list check (preferred)
// ------------------------------
// Email is missing, re-authenticate
if (!effectiveEmail) {
  return redirectToEntra(state);
}

if (!isDomainAllowed(effectiveEmail, allowedDomains))
{
  let body = { email: effectiveEmail, execution: $execution.id, allowedDomains };

  return deny403(`<div><code>${JSON.stringify(body, null, 3)}</code></div>`);
}

// ------------------------------
// Authenticated → allow workflow to continue
// ------------------------------
return $input.all().map(item => ({
  json: {
    user: {
      email: effectiveEmail
    },
    ...item.json
  }
}));

