const {headers, n8n_secrets, ...input} = $input.first().json;

// Work out which modules to include
const task = (input.query?.task || '').toLowerCase();
let includes = [];

switch(task)
{
  case "quote":
    includes = ["email", "attachment", "quote", "note_input", "quote_history", "quote_input", "quote_approval", "timeline"];
    break;
  case "quote_approval":
    includes = ["quote", "quote_approval"];
    break;
  case "completion_input":
    includes = ["completion_input"];
    break;
  default:
    includes = ["email", "attachment", "quote", "note", "note_input", "timeline", "file", "history", "quote_approval"];
}

input.query.includeModules = includes;

return {
  json: {
      ...input
  }
}
